CREATE TABLE IF NOT EXISTS valorapesquisa.responses (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), organization_id uuid NOT NULL REFERENCES valorapesquisa.organizations(id), survey_id uuid NOT NULL REFERENCES valorapesquisa.surveys(id), form_id uuid NOT NULL REFERENCES valorapesquisa.forms(id), participant_name text, participant_email text, participant_phone text, participant_document text, participant_type text, result_token_hash text UNIQUE, status text NOT NULL DEFAULT 'completed', completed_at timestamptz, created_at timestamptz NOT NULL DEFAULT now(), updated_at timestamptz NOT NULL DEFAULT now(), is_deleted boolean NOT NULL DEFAULT false);
CREATE TABLE IF NOT EXISTS valorapesquisa.response_answers (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), response_id uuid NOT NULL REFERENCES valorapesquisa.responses(id), question_id uuid NOT NULL REFERENCES valorapesquisa.questions(id), answer_json jsonb NOT NULL DEFAULT '{}'::jsonb, answer_text text, score numeric(10,2), max_score numeric(10,2), created_at timestamptz NOT NULL DEFAULT now());
